import React, { useState } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';

const Login = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post("http://localhost:5000/api/auth/login", { email, password });
      login(res.data);
      navigate("/");
    } catch (err) {
      alert("Login failed! Check your credentials.");
    }
  };

  return (
    <div className="flex justify-center items-center h-[80vh] bg-[#FAF7F2]">
      <form onSubmit={handleLogin} className="bg-white p-8 rounded-2xl shadow-lg w-80 border border-[#A5D8FF]/20">
        <h2 className="text-2xl font-bold mb-6 text-center text-gray-700">Sign In</h2>
        <input className="w-full mb-3 p-3 border border-gray-200 rounded-lg bg-[#FAF7F2] focus:outline-none focus:border-[#FFB703]" type="email" placeholder="Email" onChange={e=>setEmail(e.target.value)} />
        <input className="w-full mb-6 p-3 border border-gray-200 rounded-lg bg-[#FAF7F2] focus:outline-none focus:border-[#FFB703]" type="password" placeholder="Password" onChange={e=>setPassword(e.target.value)} />
        <button className="w-full bg-[#FFB703] text-white py-3 rounded-full font-bold hover:bg-orange-400 transition shadow-md">Continue</button>
      </form>
    </div>
  );
};

export default Login;
